sql:
SELECT AVG(w.score) AS average_score
FROM workouts w
WHERE w.program_id = (SELECT p.id FROM programs p WHERE p.name = 'Advanced Nutrition');

external_knowledge:
- 'Top 5 participants' refers to those with the highest scores within each program; 
- 'completed a distance greater than 0' means participants who have some workout data recorded; 
- 'performance rank' refers to the ranking of participants within each program based on their total score in descending order.
